// =============================================
// [NORM] 雙入口資料格式統一
// LINE Webhook 與 API 入口正規化為統一格式
// =============================================
const input = $input.first().json;
const isLine = !!input.events;

let content_text = '';
let photo_message_id = '';
let voice_message_id = '';
let source_platform = 'api';
let line_reply_token = '';
let line_user_id = '';
let farmer_phone = '';
let farmer_id = '';
let novel_name = '';
let chapter_name = '';

if (isLine) {
  source_platform = 'line';
  const event = input.events?.[0] || {};
  line_reply_token = event.replyToken || '';
  line_user_id = event.source?.userId || '';

  if (event.message?.type === 'text') {
    content_text = event.message.text || '';
  } else if (event.message?.type === 'audio') {
    voice_message_id = event.message.id || '';
    content_text = `[VOICE:${event.message.id}]`;
  } else if (event.message?.type === 'image') {
    photo_message_id = event.message.id || '';
    content_text = `[IMAGE:${event.message.id}]`;
  }
  novel_name = `LINE_${line_user_id}`;
  chapter_name = `report_${new Date().toISOString().slice(0,10)}`;
} else {
  content_text = input.body?.content || input.content || '';
  farmer_phone = input.body?.farmer_phone || input.farmer_phone || '';
  farmer_id = input.body?.farmer_id || input.farmer_id || '';
  novel_name = input.body?.novel_name || 'AgriGuard_API';
  chapter_name = input.body?.chapter_name || `report_${new Date().toISOString().slice(0,10)}`;
}

return [{
  json: {
    source_platform,
    content: content_text,
    photo_message_id,
    voice_message_id,
    has_photo: !!photo_message_id,
    has_voice: !!voice_message_id,
    farmer_phone,
    farmer_id,
    line_reply_token,
    line_user_id,
    novel_name,
    chapter_name,
    chapter_num: new Date().toISOString().slice(0,10),
    received_at: new Date().toISOString()
  }
}];

// 解析 STT 結果，提取最佳識別文字
const d = $input.first().json;
const transcript = d.results?.[0]?.alternatives?.[0]?.transcript || '';
const confidence = d.results?.[0]?.alternatives?.[0]?.confidence || 0;

return [{
  json: {
    ...d,
    // 帶回上游的 line 資訊
    source_platform: $('「NORM」雙入口資料格式統一').first()?.json?.source_platform || 'line',
    line_reply_token: $('[NORM] 雙入口資料格式統一').first()?.json?.line_reply_token || '',
    line_user_id: $('[NORM] 雙入口資料格式統一').first()?.json?.line_user_id || '',
    photo_message_id: $('[NORM] 雙入口資料格式統一').first()?.json?.photo_message_id || '',
    has_photo: $('[NORM] 雙入口資料格式統一').first()?.json?.has_photo || false,
    novel_name: $('[NORM] 雙入口資料格式統一').first()?.json?.novel_name || '',
    chapter_name: $('[NORM] 雙入口資料格式統一').first()?.json?.chapter_name || '',
    chapter_num: $('[NORM] 雙入口資料格式統一').first()?.json?.chapter_num || '',
    received_at: $('[NORM] 雙入口資料格式統一').first()?.json?.received_at || '',
    // STT 結果
    content: transcript,
    stt_transcript: transcript,
    stt_confidence: confidence,
    stt_status: transcript ? 'success' : 'empty'
  }
}];

// 建立照片直連網址，傳給 Bedrock Vision
const items = $input.all();
return items.map(item => {
  const fileId = item.json.id || '';
  const directUrl = fileId ? `https://drive.google.com/uc?export=download&id=${fileId}` : '';
  return {
    json: {
      ...item.json,
      photo_drive_url: directUrl,
      photo_file_id: fileId
    }
  };
});

// =============================================
// [PROCESS] 農損資料結構化解析
// =============================================
const item = $input.first();
let rawData = '';

try {
  const body = item.json.body || item.json;
  if (body.content && Array.isArray(body.content)) {
    rawData = body.content[0]?.text || '';
  } else if (body.completion) {
    rawData = body.completion;
  } else if (typeof body === 'string') {
    rawData = body;
  }
} catch(e) { rawData = ''; }

let parsed = {};
try {
  const clean = rawData.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  return [{ json: {
    id: $execution.id,
    report_db_id: $('任務初始化 (寫入 Supabase)').first().json[0]?.id || '',
    status: 'parse_failed',
    error_message: 'Bedrock 回應解析失敗: ' + e.message,
    raw_output: rawData,
    approval_status: 'parse_error'
  }}];
}

// 申報完整性校驗
const REQUIRED = ['crop_type','disaster_type','damage_area_ha','damage_level','location_county','location_township'];
const missing = REQUIRED.filter(f => !parsed[f] || parsed[f] === '' || parsed[f] === 0);
const confidence = parsed.confidence_score || 0;

let approval_status = 'pending_confirm';
if (missing.length === 0 && confidence >= 0.85) {
  approval_status = 'ready_to_submit';
} else if (missing.length > 0) {
  approval_status = 'need_more_info';
}

// 帶入上游農民資訊
const upstream = $('任務初始化 (寫入 Supabase)').first().json[0] || {};

return [{ json: {
  id: $execution.id,
  report_db_id: upstream.id || '',
  line_user_id: upstream.line_user_id || '',
  line_reply_token: upstream.line_reply_token || '',
  source_platform: upstream.source_platform || 'api',
  photo_drive_url: $('[BUILD] 照片直連網址建立').first()?.json?.photo_drive_url || upstream.photo_url || '',
  farmer_id: upstream.farmer_id || '',
  farmer_phone: upstream.farmer_phone || '',
  raw_content: upstream.raw_content || '',
  novel_name: upstream.novel_name || '',
  chapter_name: upstream.chapter_name || '',
  chapter_num: upstream.chapter_num || '',

  // AI 萃取欄位
  crop_type: parsed.crop_type || '',
  disaster_type: parsed.disaster_type || 'typhoon',
  damage_area_ha: parsed.damage_area_ha || 0,
  damage_level: parsed.damage_level || 1,
  damage_level_label: parsed.damage_level_label || '',
  damage_description: parsed.damage_description || '',
  growth_stage: parsed.growth_stage || '',
  location_county: parsed.location_county || '',
  location_township: parsed.location_township || '',
  dialect_terms_detected: parsed.dialect_terms_detected || [],
  photo_analysis: parsed.photo_analysis || '',
  cross_validation: parsed.cross_validation || '',
  confidence_score: confidence,
  missing_fields: missing,
  followup_question: parsed.followup_question || '',
  analysis_notes: parsed.analysis_notes || '',
  mood_color: parsed.mood_color || '#27AE60',
  music_prompt: 'peaceful rural ambient',
  approval_status,
  status: 'ai_analyzed'
}}];

// 產生確認訊息（資料完整 or 信心不足）
const d = $input.first().json;
const damageLabel = ['', '輕微 (1-30%)', '中等 (30-70%)', '嚴重 (70-90%)', '全損 (90-100%)'];
const disasterMap = { typhoon:'颱風', flood:'豪雨/淹水', drought:'乾旱', cold_injury:'低溫寒害', pest:'病蟲害', hail:'冰雹' };
const rptId = `AGR-${new Date().toISOString().slice(0,10).replace(/-/g,'')}-${String(d.report_db_id).slice(-4).padStart(4,'0')}`;

const msg = [
  `✅ 農損申報資料確認`,
  ``,
  `📋 申報編號：${rptId}`,
  ``,
  `🌾 作物種類：${d.crop_type || '未偵測'}`,
  `🌀 災害類型：${disasterMap[d.disaster_type] || d.disaster_type}`,
  `📐 受損面積：${d.damage_area_ha} 公頃`,
  `📊 損失程度：${damageLabel[d.damage_level] || d.damage_level_label}`,
  `📍 地點：${d.location_county}${d.location_township}`,
  d.photo_analysis ? `\n📷 照片分析：${d.photo_analysis}` : '',
  ``,
  `✨ 資料完整！請回覆「確認送出」即可完成申報，或回覆「修改」來調整內容。`
].filter(l => l !== undefined).join('\n');

return [{ json: { ...d, confirm_message: msg, report_number: rptId, quick_replies: ['確認送出', '修改資料', '聯絡志工'] } }];

// 產生容錯追問訊息（缺欄位時）
const d = $input.first().json;
const fieldLabels = { crop_type:'作物種類', disaster_type:'災害類型', damage_area_ha:'受損面積', damage_level:'損失程度', location_county:'縣市', location_township:'鄉鎮' };
const missingLabels = (d.missing_fields || []).map(f => fieldLabels[f] || f);

let quickReplies = ['嘉義縣水上鄉', '雲林縣虎尾鎮', '彰化縣溪湖鎮', '其他（請說明）'];
if (d.missing_fields?.includes('damage_area_ha')) quickReplies = ['不到0.1公頃', '0.1-0.5公頃', '0.5-1公頃', '超過1公頃'];
if (d.missing_fields?.includes('damage_level')) quickReplies = ['輕微（少部分）', '中等（一半左右）', '嚴重（大部分）', '全損（幾乎全滅）'];

const msg = [
  `阿公/阿嬤，謝謝您的回報！😊`,
  ``,
  `我還需要以下資料才能幫您申報：`,
  ...missingLabels.map(l => `❓ ${l}`),
  ``,
  d.followup_question || '請用說話或打字告訴我喔！'
].join('\n');

return [{ json: { ...d, followup_message: msg, quick_replies: quickReplies } }];

// 人工轉介（解析失敗防線）
const d = $input.first().json;
const msg = [
  `阿公/阿嬤，您好！`,
  ``,
  `我們已收到您的農損通報，但因為訊息比較複雜，`,
  `我們會請水上鄉農會的志工在今天內打電話給您協助申報。`,
  ``,
  `若有急需，也可撥打 1955 農業專線。`,
  `感謝您的耐心！🌾`
].join('\n');
return [{ json: { ...d, escalate_message: msg, quick_replies: ['好的謝謝'] } }];

