// =============================================
// [BUILD] 建構政府農損申報 JSON
// 映射至農業部災損申報系統標準 Schema
// =============================================
const d = $input.first().json?.[0] || $input.first().json;

const disasterCodeMap = { typhoon:'D01', flood:'D02', drought:'D03', cold_injury:'D04', pest:'D05', hail:'D06' };
const cropCodeMap = { '水稻':'C001', '玉米':'C002', '香蕉':'C003', '鳳梨':'C004', '番茄':'C005', '高麗菜':'C006', '芋頭':'C007', '絲瓜':'C008', '甘蔗':'C009', '大豆':'C010' };

const reportDate = new Date().toISOString().slice(0,10);
const rptId = `AGR-${reportDate.replace(/-/g,'')}-${String(d.id || '0000').slice(-4).padStart(4,'0')}`;

const govPayload = {
  report_id: rptId,
  submitted_at: new Date().toISOString(),
  report_type: 'disaster_damage',
  report_source: d.source_platform === 'line' ? 'LINE_DIGITAL_INCLUSION' : 'WEB_API',
  farmer: {
    id: d.farmer_id || d.line_user_id || '',
    phone: d.farmer_phone || '',
    contact_method: d.source_platform
  },
  location: {
    county: d.location_county,
    township: d.location_township
  },
  disaster: {
    type: d.disaster_type,
    type_code: disasterCodeMap[d.disaster_type] || 'D99',
    report_date: reportDate
  },
  crop: {
    name: d.crop_type,
    code: cropCodeMap[d.crop_type] || 'C999',
    growth_stage: d.growth_stage
  },
  damage: {
    area_ha: d.damage_area_ha,
    level: d.damage_level,
    level_label: d.damage_level_label,
    description: d.damage_description
  },
  ai_evidence: {
    photo_url: d.photo_url || '',
    raw_input: d.raw_content || '',
    dialect_terms: d.dialect_terms_detected || [],
    photo_analysis: d.photo_analysis || '',
    cross_validation: d.cross_validation || '',
    confidence_score: d.confidence_score,
    generated_by: 'AWS Bedrock Claude 3.7 Sonnet'
  },
  status: 'submitted_pending_inspection'
};

return [{ json: { ...d, gov_payload: govPayload, report_id: rptId } }];

