const body = $json.body;

if (!body || !body.commits || body.commits.length === 0) {
    return { _skip: true, reason: '非標準 Push 事件或無 Commit 資料' };
}

const lastCommitMessage = body.commits[body.commits.length - 1].message;
if (lastCommitMessage.includes('[n8n-sync]')) {
    return { _skip: true, reason: '偵測到 n8n 自發變更，已自動終止流程避免死迴圈' };
}

const hasWorkflowChanges = body.commits.some(commit => {
    const allFiles = [...commit.added, ...commit.modified];
    return allFiles.some(file => file.startsWith('workflows/') && file.endsWith('.json'));
});

if (!hasWorkflowChanges) {
    return { _skip: true, reason: '本次 Commit 未變更任何工作流 JSON 檔案' };
}

const targetCommit = body.commits[body.commits.length - 1];
const targetFile = [...targetCommit.added, ...targetCommit.modified].find(file => file.startsWith('workflows/') && file.endsWith('.json'));
const workflowName = targetFile.replace('workflows/', '').replace('.json', '');

return {
    _skip: false,
    filePath: targetFile,
    workflowName: workflowName,
    commitMessage: lastCommitMessage
};

let data = $json;

// 如果資料被包在 data 陣列裡，先取出來
if (data.data && Array.isArray(data.data)) {
  data = data.data[0];
}

// 清除每個 node 裡的 credentials 欄位
if (data.nodes && Array.isArray(data.nodes)) {
  data.nodes = data.nodes.map(node => {
    const cleanedNode = { ...node };
    if (cleanedNode.credentials) {
      delete cleanedNode.credentials;
    }
    // 同時檢查 parameters 裡是否有寫死的敏感字串
    return cleanedNode;
  });
}

return data;
